/**
 * Unit tests for lifecycle/telemetry-dark-check (#2590)
 */

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import { mkdirSync, mkdtempSync, rmSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';
import { tmpdir } from 'node:os';
import { telemetryDarkCheck, _internals } from '../lifecycle/telemetry-dark-check.js';
import { NOOP_CTX } from '../lib/context.js';
import type { HookInput } from '../types.js';

const URL_VAR = 'ORCHESTKIT_HOOK_URL';
const TOKEN_VAR = 'ORCHESTKIT_HOOK_TOKEN';
const OPT_OUT = 'ORK_NO_TELEMETRY_DARK_WARN';
const PLUGIN_DATA = 'CLAUDE_PLUGIN_DATA';
const PROJECT_DIR = 'CLAUDE_PROJECT_DIR';

const SAVED = [URL_VAR, TOKEN_VAR, OPT_OUT, PLUGIN_DATA, PROJECT_DIR] as const;

describe('lifecycle/telemetry-dark-check (#2590)', () => {
  let tmp: string;
  let stderrSpy: ReturnType<typeof vi.spyOn>;
  const saved: Record<string, string | undefined> = {};

  beforeEach(() => {
    tmp = mkdtempSync(join(tmpdir(), 'telemetry-dark-'));
    stderrSpy = vi.spyOn(process.stderr, 'write').mockImplementation(() => true);
    for (const k of SAVED) {
      saved[k] = process.env[k];
      delete process.env[k];
    }
  });

  afterEach(() => {
    stderrSpy.mockRestore();
    for (const k of SAVED) {
      if (saved[k] !== undefined) process.env[k] = saved[k];
      else delete process.env[k];
    }
    try {
      rmSync(tmp, { recursive: true, force: true });
    } catch {
      /* best-effort */
    }
  });

  const input = (): HookInput => ({
    hook_event: 'SessionStart',
    project_dir: tmp,
  }) as HookInput;

  /** Seed <tmp>/.claude/telemetry with a .jsonl file of the given byte size. */
  function seedTelemetry(bytes: number, name = 'events.jsonl'): void {
    const dir = join(tmp, '.claude', 'telemetry');
    mkdirSync(dir, { recursive: true });
    writeFileSync(join(dir, name), 'x'.repeat(bytes));
  }

  it('warns when TOKEN set, URL unset, and backlog exceeds threshold', () => {
    process.env[TOKEN_VAR] = 'tok';
    seedTelemetry(_internals.BACKLOG_WARN_BYTES + 1);

    const result = telemetryDarkCheck(input(), NOOP_CTX);

    expect(result).toEqual({ continue: true, suppressOutput: true });
    expect(stderrSpy).toHaveBeenCalledOnce();
    const msg = String(stderrSpy.mock.calls[0][0]);
    expect(msg).toContain(URL_VAR);
    expect(msg).toContain('#2590');
  });

  it('stays silent in the default local-only mode (neither var set)', () => {
    seedTelemetry(_internals.BACKLOG_WARN_BYTES + 1);
    telemetryDarkCheck(input(), NOOP_CTX);
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('stays silent when both TOKEN and URL are set (healthy)', () => {
    process.env[TOKEN_VAR] = 'tok';
    process.env[URL_VAR] = 'https://ingest.example';
    seedTelemetry(_internals.BACKLOG_WARN_BYTES + 1);
    telemetryDarkCheck(input(), NOOP_CTX);
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('stays silent when backlog is below the threshold', () => {
    process.env[TOKEN_VAR] = 'tok';
    seedTelemetry(1024); // 1 KiB « 64 KiB
    telemetryDarkCheck(input(), NOOP_CTX);
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('stays silent when the telemetry dir is empty/absent', () => {
    process.env[TOKEN_VAR] = 'tok';
    telemetryDarkCheck(input(), NOOP_CTX);
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('honours the opt-out env var', () => {
    process.env[TOKEN_VAR] = 'tok';
    process.env[OPT_OUT] = '1';
    seedTelemetry(_internals.BACKLOG_WARN_BYTES + 1);
    telemetryDarkCheck(input(), NOOP_CTX);
    expect(stderrSpy).not.toHaveBeenCalled();
  });

  it('resolveTelemetryDir prefers CLAUDE_PLUGIN_DATA over project dir', () => {
    process.env[PLUGIN_DATA] = '/data';
    expect(_internals.resolveTelemetryDir('/proj')).toBe('/data/telemetry');
  });

  it('resolveTelemetryDir rejects JSON-poisoned project dir (#1250)', () => {
    expect(_internals.resolveTelemetryDir('{"continue":true}')).toBeNull();
  });
});
